SELECT DISTINCT m.menu_id, m.menu_name, m.parent_id, m.order_num, m.path, m.component, m.menu_type, m.perms, m.icon, m.visible, m.status, m.menu_location FROM sys_menu m INNER JOIN sys_role_menu rm ON m.menu_id = rm.menu_id WHERE rm.role_id IN
#{rid}
AND m.status = '0' ORDER BY m.parent_id, m.order_num

SELECT DISTINCT m.perms FROM sys_menu m INNER JOIN sys_role_menu rm ON m.menu_id = rm.menu_id WHERE rm.role_id IN
#{rid}
AND m.status = '0' AND m.perms IS NOT NULL AND m.perms != ''

SELECT menu_id, menu_name, parent_id, order_num, path, component, menu_type, perms, icon, visible, status, menu_location FROM sys_menu WHERE menu_id IN
#{mid}
ORDER BY parent_id, order_num
